// src/views/user/MyProfile/composables/useLoading.js
import { ref } from 'vue'

export function useLoading() {
  const loading = ref(false)

  const withLoading = async (fn) => {
    loading.value = true
    try {
      await fn()
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    withLoading
  }
}
